// src/components/PopularProducts.js
import React, { useEffect, useState } from "react";
import productsData from "../data/ProductData";
import "./index.css";

function PopularProducts() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // ✅ Replace with your backend API URL
    const apiUrl = "http://localhost:5000/api/products";

    fetch(apiUrl)
      .then((res) => res.json())
      .then((data) => {
        if (Array.isArray(data) && data.length > 0) {
          setProducts(data); // show DB data
        } else {
          setProducts(productsData); // fallback to dummy
        }
        setLoading(false);
      })
      .catch((err) => {
        console.error("Error fetching products:", err);
        setProducts(productsData); // fallback on error
        setLoading(false);
      });
  }, []);

  return (
    <div className="popular-products">
      <h2>Popular Products</h2>

      {loading ? (
        <p>Loading products...</p>
      ) : (
        <div className="product-grid">
          {products.slice(0, 8).map((product, index) => (
            <div className="product-card" key={product._id || index}>
              <img src={product.image} alt={product.name} />
              <h3>{product.name}</h3>
              <p className="price">₹{product.price}</p>
              <p className="rating">⭐ {product.rating}</p>
              <button>Buy Now</button>
            </div>
          ))}
        </div>
      )}

      {/* Featured Picks Section */}
      <div className="featured-picks">
        <h2>Featured Picks</h2>
        <div className="picks-grid">
          <div
            className="pick-card"
            style={{
              backgroundImage:
                "url(https://images.pexels.com/photos/13145328/pexels-photo-13145328.jpeg)",
            }}
          >
            <h3>Best in Sound</h3>
            <p>Discover the latest sound systems</p>
          </div>
          <div
            className="pick-card"
            style={{
              backgroundImage:
                "url(https://images.pexels.com/photos/3394659/pexels-photo-3394659.jpeg)",
            }}
          >
            <h3>Stylish Earphones</h3>
            <p>Experience crystal clear sound</p>
          </div>
          <div
            className="pick-card"
            style={{
              backgroundImage:
                "url(https://images.pexels.com/photos/5082570/pexels-photo-5082570.jpeg)",
            }}
          >
            <h3>Gaming Laptops</h3>
            <p>Powerful machines for gaming</p>
          </div>
        </div>
      </div>

      {/* Gaming Banner */}
      <div className="gaming-banner">
        <img
          src="https://images.pexels.com/photos/3945658/pexels-photo-3945658.jpeg"
          alt="Gaming Setup"
        />
        <div className="banner-text">
          <h2>Level Up Your Gaming Experience</h2>
          <p>Get the best gaming accessories and gear.</p>
        </div>
      </div>

      {/* Subscribe Section */}
      <div className="subscribe-section">
        <h2>Subscribe for Latest Deals</h2>
        <input type="email" placeholder="Enter your email" />
        <button>Subscribe</button>
      </div>
    </div>
  );
}

export default PopularProducts;
